() => {
  const btn = document.querySelector("gs-nav-button[data-qa-id='planning'] a.nav-button");
  const label = btn?.querySelector('gs-icon')?.getAttribute('aria-label') || '';
  const tip =
    Array.from(document.querySelectorAll('gs-tooltip')).find(t => {
      const txt = (t.textContent || '').trim();
      return txt && (!label || txt.includes(label));
    }) || document.querySelector('gs-tooltip');
  if (!btn || !tip) return;

  const tipWrap = tip.closest('.cdk-overlay-connected-position-bounding-box');
  if (tipWrap) {
    tipWrap.style.left = '0px';
    tipWrap.style.top = '0px';
    tipWrap.style.width = '100vw';
    tipWrap.style.height = '100vh';
    tipWrap.style.position = 'fixed';
    tipWrap.style.display = 'block';
    tipWrap.style.transform = 'none';
  }

  const pane = tip.closest('.cdk-overlay-pane');
  if (pane) {
    pane.style.position = 'fixed';
    pane.style.transform = 'none';
  }

  tip.style.position = 'fixed';
  tip.style.margin = '0';
  tip.style.transform = 'none';

  const br = btn.getBoundingClientRect();
  const tr = tip.getBoundingClientRect();
  const left = Math.max(8, Math.round(br.left + (br.width / 2) - (tr.width / 2)));
  const top = Math.round(br.bottom + 10);

  tip.style.left = `${left}px`;
  tip.style.top = `${top}px`;
}
